class Shape {
    public double area() { return 0; }
}

class Circle extends Shape {
    private double radius;
    public Circle(double r) { this.radius = r; }
    @Override public double area() { return Math.PI * radius * radius; }
}

class Rectangle extends Shape {
    private double width, height;
    public Rectangle(double w, double h) { this.width = w; this.height = h; }
    @Override public double area() { return width * height; }
}

public class App {
    public static double totalArea(Shape[] shapes) {
        double total = 0;
        for (Shape s : shapes) total += s.area();
        return total;
    }

    public static void main(String[] args) {
        Shape[] shapes = { new Circle(5), new Rectangle(4, 3), new Circle(3) };
        System.out.println("Total area: " + totalArea(shapes));
    }
}

class Employee {
    protected String name;
    protected double baseSalary;

    public Employee(String name, double baseSalary) {
        this.name = name;
        this.baseSalary = baseSalary;
    }

    public double calculateSalary() { return baseSalary; }
    public String getName() { return name; }
}

class Manager extends Employee {
    private double bonus;
    public Manager(String name, double base, double bonus) {
        super(name, base);
        this.bonus = bonus;
    }
    @Override public double calculateSalary() { return baseSalary + bonus; }
}

class Contractor extends Employee {
    private double hourlyRate;
    private int hoursWorked;
    public Contractor(String name, double hourlyRate, int hoursWorked) {
        super(name, 0);
        this.hourlyRate = hourlyRate;
        this.hoursWorked = hoursWorked;
    }
    @Override public double calculateSalary() { return hourlyRate * hoursWorked; }
}

public class App {
    public static void printPayroll(Employee[] staff) {
        for (Employee e : staff) {
            System.out.println(e.getName() + ": ₹" + e.calculateSalary());
        }
    }

    public static void main(String[] args) {
        Employee[] staff = {
            new Employee("Aisha", 75000),
            new Manager("Raj", 85000, 15000),
            new Contractor("Priya", 2500, 23)
        };
        printPayroll(staff);
    }
}

