class Income {
    protected double amount;
    public Income(double amount) { this.amount = amount; }
    public double taxDue() { return 0; }
}

class SalaryIncome extends Income {
    public SalaryIncome(double amount) { super(amount); }
    @Override public double taxDue() { return amount * 0.20; }
}

class FreelanceIncome extends Income {
    public FreelanceIncome(double amount) { super(amount); }
    @Override public double taxDue() { return amount * 0.15; }
}

class RentalIncome extends Income {
    public RentalIncome(double amount) { super(amount); }
    @Override public double taxDue() { return amount * 0.10; }
}

public class App {
    public static double totalTax(Income[] sources) {
        double total = 0;
        for (Income inc : sources) total += inc.taxDue();
        return total;
    }

    public static void main(String[] args) {
        Income[] income = {
            new SalaryIncome(60000),    // 60000 × 0.20 = 12000
            new FreelanceIncome(40000), // 40000 × 0.15 = 6000
            new RentalIncome(30000)     // 30000 × 0.10 = 3000
        };
        System.out.println("Total tax: ₹" + totalTax(income));
    }
}

