class Logger {
    protected String logLevel;
    public Logger(String logLevel) { this.logLevel = logLevel; }
    public void log(String msg) { System.out.println("[" + logLevel + "] " + msg); }
}

class ConsoleLogger extends Logger {
    public ConsoleLogger(String logLevel) { super(logLevel); }
    @Override public void log(String msg) {
        System.out.println("[CONSOLE][" + logLevel + "] " + msg);
    }
}

class FileLogger extends Logger {
    private String filename;
    public FileLogger(String logLevel, String filename) {
        super(logLevel);
        this.filename = filename;
    }
    @Override public void log(String msg) {
        System.out.println("[FILE: " + filename + "][" + logLevel + "] " + msg);
    }
}

class NullLogger extends Logger {
    public NullLogger() { super("NULL"); }
    @Override public void log(String msg) { /* intentionally silent */ }
}

public class App {
    public static void logAll(Logger logger, String[] messages) {
        for (String msg : messages) logger.log(msg);
    }

    public static void main(String[] args) {
        String[] msgs = { "Starting app", "User logged in" };

        logAll(new ConsoleLogger("INFO"), msgs);
        logAll(new NullLogger(), msgs);  // silent
    }
}

class Discount {
    public double apply(double price) { return price; }
}

class PercentageDiscount extends Discount {
    private double percent;
    public PercentageDiscount(double percent) { this.percent = percent; }
    @Override public double apply(double price) { return price * (1 - percent / 100); }
}

class FlatDiscount extends Discount {
    private double amount;
    public FlatDiscount(double amount) { this.amount = amount; }
    @Override public double apply(double price) { return Math.max(0, price - amount); }
}

class BuyOneGetOneFree extends Discount {
    @Override public double apply(double price) { return price / 2; }
}

public class App {
    public static double checkout(double price, Discount[] discounts) {
        for (Discount d : discounts) {
            price = d.apply(price);
        }
        return price;
    }

    public static void main(String[] args) {
        Discount[] offers = {
            new PercentageDiscount(10),  // 1000 → 900
            new FlatDiscount(50)          // 900 → 850
        };
        double finalPrice = checkout(1000, offers);
        System.out.println("Final price: ₹" + finalPrice);
    }
}

class Event {
    private String type;
    private long timestamp;

    public Event(String type) {
        this.type = type;
        this.timestamp = System.currentTimeMillis();
    }

    public String getType() { return type; }
    public long getTimestamp() { return timestamp; }

    @Override public String toString() {
        return "[" + type + "] (at " + timestamp + ")";
    }
}

class LoginEvent extends Event {
    private String username;
    public LoginEvent(String username) {
        super("LOGIN");
        this.username = username;
    }
    public String getUsername() { return username; }
    @Override public String toString() {
        return "[LOGIN] " + username + " (at " + getTimestamp() + ")";
    }
}

class PurchaseEvent extends Event {
    private double amount;
    private String productName;
    public PurchaseEvent(String productName, double amount) {
        super("PURCHASE");
        this.productName = productName;
        this.amount = amount;
    }
    public double getAmount() { return amount; }
    @Override public String toString() {
        return "[PURCHASE] " + productName + " ₹" + amount + " (at " + getTimestamp() + ")";
    }
}

class EventHandler {
    public void handle(Event e) {
        System.out.println("Handling event: " + e);
    }
}

class AuditHandler extends EventHandler {
    @Override public void handle(Event e) {
        System.out.println("AUDIT: " + e);
    }
}

class AlertHandler extends EventHandler {
    @Override public void handle(Event e) {
        if (e instanceof PurchaseEvent pe && pe.getAmount() > 10000) {
            System.out.println("ALERT: Large purchase: " + pe);
        }
    }
}

public class App {
    public static void main(String[] args) {
        EventHandler[] handlers = { new AuditHandler(), new AlertHandler() };
        Event[] events = {
            new LoginEvent("aisha"),
            new PurchaseEvent("Laptop", 75000),
            new PurchaseEvent("Coffee", 150)
        };

        for (EventHandler handler : handlers) {
            for (Event event : events) {
                handler.handle(event);
            }
        }
    }
}
